      expiresAt: coupon.expiresAt == null ? Number.POSITIVE_INFINITY : +coupon.expiresAt,
      maxRedemptions: coupon.maxRedemptions == null ? 1 : +coupon.maxRedemptions,
      redeemedCount: coupon.redeemedCount == null ? 0 : +coupon.redeemedCount,
      scope: coupon.scope === 'perUser' ? 'perUser' : 'global', // global: one-time or limited total uses; perUser: each user once up to maxRedemptions total
      discountType: coupon.discountType === 'percent' ? 'percent' : 'amount',
      discountValue: +coupon.discountValue,
      currency: coupon.currency || 'USD',
      metadata: coupon.metadata || {},
