    if (!userId) return { ok: false, reason: 'INVALID_USER' };
    if (!Number.isFinite(orderTotalCents) || orderTotalCents <= 0) return { ok: false, reason: 'INVALID_ORDER_TOTAL' };
    currency = (currency || 'USD').toUpperCase();

