      this._coupons.set(code, c);

      const finalTotalCents = Math.max(0, Math.round(orderTotalCents - discountCents));
      return {
        ok: true,
        code: c.code,
        discountType: c.discountType,
        discountValue: c.discountValue,
        discountCents,
        finalTotalCents,
        redeemedCount: c.redeemedCount,
        maxRedemptions: c.maxRedemptions,
        scope: c.scope,
      };
